var plans = $input.all().map(function(i) { return i.json; });
var results = [];

plans.forEach(function(p) {
  var sol = p.sol_num || '';
  if (!sol || sol.startsWith('MAS-')) return; // Skip synthetic sol numbers

  // Flag for amendment check - in production this would query GovTribe
  // For now, flag plans that haven't been compliance-checked in 7+ days
  var lastChecked = p.last_checked ? new Date(p.last_checked) : new Date('2020-01-01');
  var daysSince = Math.floor((Date.now() - lastChecked.getTime()) / 86400000);

  if (daysSince >= 7) {
    results.push({
      json: {
        plan_id: p.id,
        opportunity: p.opportunity,
        agency: p.agency,
        sol_num: sol,
        stage: p.stage,
        days_since_check: daysSince,
        needs_refresh: true
      }
    });
  }
});

if (results.length === 0) return [{json:{skip:true, reason:'all_plans_recently_checked'}}];
return results;
